const a={models:new Map,availability:new Map},l={models:300*1e3,availability:30*1e3};export function getCachedModels(e){const t=a.models.get(e);return t&&Date.now()-t.timestamp<l.models?t.models:null}export function setCachedModels(e,t){a.models.set(e,{models:t,timestamp:Date.now()})}export function getCachedAvailability(e){const t=a.availability.get(e);return t&&Date.now()-t.timestamp<l.availability?t.available:null}export function setCachedAvailability(e,t){a.availability.set(e,{available:t,timestamp:Date.now()})}export function clearProviderCache(e){e?(a.models.delete(e),a.availability.delete(e)):(a.models.clear(),a.availability.clear())}
